const inputs = document.querySelectorAll('input[type="text"], input[type="date"], input, [role="combobox"]');
const result = [];
inputs.forEach((inp, idx) => {
  result.push({
    index: idx,
    type: inp.type || inp.tagName,
    placeholder: inp.placeholder,
    value: inp.value,
